bomData.valueScript:
// Type of the Bom-Element (will be checked in order output)
  let elementType='Hardware';

  // ProductionSite Category (to split the orders for different production sites)
  let elementCategory='';

  // Id of the parent to create the hierarchy
  let parentBomId = part.pa_ParentName;

   // Parse the json string
    const hardwareIdElements = JSON.parse(part.pa_HardwareId) as { values: string[] };

    // Check if the json got a valid format
    if (!Array.isArray(hardwareIdElements.values)) {
      throw new Error("Could not create the BOM for the Pullout fittings");
    }

    // Iterate throug the hardware elements
    for (const hardwareId of hardwareIdElements.values) {

      // Check if we should add an entry
      if (hardwareId !== "None") {
          // Call the function to process the Bom-Element
        GlobalFunc.process_HardwareBom(this, part, elementType, elementCategory, parentBomId, hardwareId)
      }
    }
